router.post('/join', authMiddleware, (req, res) => {
	const { checkinId, content } = req.body;
	const item = db.prepare('SELECT id FROM checkins WHERE id = ? AND status = 1').get(checkinId);
	if (!item) return res.json({ code: 404, msg: '不存在' });
	const today = getLocalDateString();
	const existing = db.prepare('SELECT id FROM checkin_records WHERE checkin_id = ? AND user_id = ? AND day = ?').get(checkinId, req.userId, today);
	if (existing) return res.json({ code: 200, msg: '今日已打卡', data: { alreadyDone: true } });

	db.prepare('INSERT INTO checkin_records (checkin_id, user_id, day, content) VALUES (?, ?, ?, ?)').run(checkinId, req.userId, today, trimText(content, 2000));
	db.prepare('UPDATE checkins SET join_cnt = join_cnt + 1 WHERE id = ?').run(checkinId);
	res.json({ code: 200, msg: '打卡成功' });
});

router.post('/invite', authMiddleware, (req, res) => {
	const { targetId } = req.body;
	const target = db.prepare('SELECT id FROM users WHERE id = ?').get(targetId);
	if (!target) return res.json({ code: 404, msg: '用户不存在' });
	if (Number(targetId) === req.userId) return res.json({ code: 400, msg: '不能邀请自己' });

	const partnerError = assertPartnerAvailability(db, req.userId, Number(targetId));
	if (partnerError) return res.json(partnerError);

	const existing = db.prepare(
		`SELECT id, status FROM partners
		 WHERE ((user_id = ? AND target_id = ?) OR (user_id = ? AND target_id = ?))
		 AND status IN (0, 1)
		 ORDER BY status DESC, updated_at DESC, created_at DESC
		 LIMIT 1`
	).get(req.userId, targetId, targetId, req.userId);
	if (existing) {
		if (existing.status === 1) return res.json({ code: 200, msg: '已是学伴' });
		return res.json({ code: 200, msg: '邀请已发送，等待对方确认' });
	}

	// 清除旧的拒绝记录，允许重新邀请
	db.prepare(
		`DELETE FROM partners
		 WHERE ((user_id = ? AND target_id = ?) OR (user_id = ? AND target_id = ?)) AND status NOT IN (0, 1)`
	).run(req.userId, targetId, targetId, req.userId);

	const result = db.prepare('INSERT INTO partners (user_id, target_id, status) VALUES (?, ?, 0)').run(req.userId, targetId);
	notifyPartnerInvite(req.userId, targetId);
	res.json({ code: 200, data: { id: result.lastInsertRowid } });
});

router.delete('/user_del/:id', adminAuth, (req, res) => {
	const user = db.prepare('SELECT id FROM users WHERE id = ?').get(req.params.id);
	if (!user) return res.json({ code: 404, msg: '用户不存在' });
	const deleteUser = db.transaction((userId) => {
		db.prepare('DELETE FROM messages WHERE user_id = ? OR from_id = ?').run(userId, userId);
		db.prepare('DELETE FROM plan_records WHERE user_id = ?').run(userId);
		db.prepare('DELETE FROM plans WHERE creator_id = ? OR executor_id = ?').run(userId, userId);
		db.prepare('UPDATE checkins SET supervisor_id = 0, supervisor_name = "" WHERE supervisor_id = ?').run(userId);
		db.prepare('UPDATE checkins SET creator_id = 0 WHERE creator_id = ?').run(userId);
		db.prepare('DELETE FROM comments WHERE user_id = ?').run(userId);
		db.prepare('DELETE FROM likes WHERE user_id = ?').run(userId);
		db.prepare('DELETE FROM favorites WHERE user_id = ?').run(userId);
		db.prepare('DELETE FROM signs WHERE user_id = ?').run(userId);
		db.prepare('DELETE FROM checkin_records WHERE user_id = ?').run(userId);
		db.prepare('DELETE FROM partners WHERE user_id = ? OR target_id = ?').run(userId, userId);
		const notes = db.prepare('SELECT id FROM notes WHERE user_id = ?').all(userId);
		notes.forEach(n => deleteNoteCascade(db, n.id));
		db.prepare('DELETE FROM users WHERE id = ?').run(userId);
	});
	deleteUser(req.params.id);
	res.json({ code: 200, msg: '删除成功' });
});
